const STYLE = `
  @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@700&family=DM+Sans:wght@300;400;500;600&display=swap');
  :root { --brand:#e03030; --brand-dark:#b91c1c; }
  .hero-gradient { background: linear-gradient(135deg,#fff7f7 0%,#f0f9ff 50%,#fff5f5 100%); }
  .text-brand { color: var(--brand); }
  .bg-brand { background-color: var(--brand); }

  .btn-primary {
    transition: transform .2s, box-shadow .2s;
    box-shadow: 0 4px 20px rgba(224,48,48,.35);
  }
  .btn-primary:hover { transform:translateY(-2px); box-shadow:0 8px 28px rgba(224,48,48,.45); }
  .btn-secondary:hover { border-color:var(--brand)!important; color:var(--brand)!important; }

  @keyframes pulseRing {
    0%,100%{ opacity:.5; transform:scale(1); }
    50%    { opacity:.15; transform:scale(1.07); }
  }
  .pulse-ring { animation:pulseRing 3s ease-in-out infinite; }

  @keyframes floatBob {
    0%,100%{ transform:translateY(0); }
    50%    { transform:translateY(-7px); }
  }
  .float-bob { animation:floatBob 4s ease-in-out infinite; }
  .float-bob-delay { animation:floatBob 4s ease-in-out infinite 2s; }

  @keyframes xrayGlow {
    0%,100%{
      filter:
        drop-shadow(0 0 6px rgba(224,48,48,.9))
        drop-shadow(0 0 18px rgba(224,48,48,.6))
        drop-shadow(0 0 40px rgba(224,48,48,.3));
    }
    50%{
      filter:
        drop-shadow(0 0 12px rgba(255,100,100,1))
        drop-shadow(0 0 35px rgba(224,48,48,.85))
        drop-shadow(0 0 70px rgba(224,48,48,.5));
    }
  }
  .xray-glow { animation:xrayGlow 3s ease-in-out infinite; }

  @keyframes skelShimmer {
    0%,100%{ opacity:.5; }
    50%    { opacity:1; }
  }
  .sk  { animation:skelShimmer 3s ease-in-out infinite; }
  .sk2 { animation:skelShimmer 3s ease-in-out infinite 1.5s; }

  @keyframes orbPulse {
    0%,100%{ opacity:.5; transform:scale(1); }
    50%    { opacity:1;   transform:scale(1.6); }
  }
  .orb  { animation:orbPulse 2s ease-in-out infinite; transform-box:fill-box; transform-origin:center; }
  .od1  { animation-delay:.4s; }
  .od2  { animation-delay:.8s; }
  .od3  { animation-delay:1.2s; }
  .od4  { animation-delay:1.6s; }

  @keyframes scanDown {
    0%  { transform:translateY(-10px); opacity:0; }
    5%  { opacity:.7; }
    95% { opacity:.7; }
    100%{ transform:translateY(310px); opacity:0; }
  }
  .scan { animation:scanDown 4s linear infinite; }

  @keyframes bgPulse {
    0%,100%{ opacity:.5; }
    50%    { opacity:1; }
  }
  .bg-pulse { animation:bgPulse 3s ease-in-out infinite; }
`;

const Stars = ({ count = 5 }) => (
  <div className="flex gap-0.5">
    {Array.from({ length: count }).map((_, i) => (
      <svg key={i} className="w-4 h-4 text-amber-400" fill="currentColor" viewBox="0 0 20 20">
